bool solve(vector<int>& a, int maxw) {
    int n = a.size();
    vector<int> dp(n + 1, 0);
    dp[0] = 0;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= maxw; j++) {
            if (a[i - 1] <= j) {
                dp[i] = max(dp[i - 1], dp[i - 1] + 1);
            } else {
                dp[i] = max(dp[i - 1], dp[i - 1]);
            }
        }
    }
    return max(dp[n], 0);
}
};

