import sys
from functools import lru_cache

class Solution:
    def solve(self, a: list[int], maxw: int) -> int:
        n = len(a)
        @lru_cache(None)
        def dp(i, w):
            if i == 0:
                return 0 if w == 0 else float('inf')
            if w < 0:
                return float('inf')
            return min(dp(i - 1, w), dp(i - 1, w - a[i - 1]) + 1)
        return dp(n - 1, maxw)

if __name__ == '__main__':
    input = sys.stdin.readline
    n = int(input())
    a = list(map(int, input().split()))
    maxw = int(input())
    print(Solution().solve(a, maxw))

